// === Pick near-term expirations and build the streamer-symbol list ===
// Inputs: option chain (nested) from previous node
// Output: { symbol, expirations: [...], streamerSymbols: [...] } per item

const cfg = $('Extract Session Token').first().json.config;
const maxDTE = cfg.maxDTE ?? 7;
const bandPct = cfg.strikeBandPct ?? 0.07;

const out = [];
for (const item of items) {
  const data = item.json?.data;
  if (!data || !data.items || !data.items.length) continue;
  const root = data.items[0];
  const underlying = root['underlying-symbol'];

  // Underlying mark from market-metrics paired by index in next merge step;
  // for now keep a placeholder — actual price merged downstream.
  const expirations = (root.expirations || [])
    .filter(e => {
      const dte = Math.ceil((new Date(e['expiration-date']) - Date.now()) / 86400000);
      return dte >= 0 && dte <= maxDTE;
    })
    .slice(0, 2); // 0DTE + next expiration

  const streamerSymbols = [];
  const strikeIndex = [];
  for (const exp of expirations) {
    for (const s of (exp.strikes || [])) {
      if (s['call-streamer-symbol']) streamerSymbols.push(s['call-streamer-symbol']);
      if (s['put-streamer-symbol']) streamerSymbols.push(s['put-streamer-symbol']);
      strikeIndex.push({
        expiration: exp['expiration-date'],
        strike: parseFloat(s['strike-price']),
        callStreamer: s['call-streamer-symbol'],
        putStreamer: s['put-streamer-symbol'],
        callSymbol: s.call,
        putSymbol: s.put,
      });
    }
  }

  out.push({
    json: {
      symbol: underlying,
      bandPct,
      maxDTE,
      expirations: expirations.map(e => e['expiration-date']),
      strikeIndex,
      streamerSymbols,
    }
  });
}
return out;

// === Wall detection, volume filter, trend signal, scoring ===
// Combines: snapshot quotes (this node's input), strikeIndex (from Pick Near-Term),
// and market-metrics (looked up via $('Get Market Metrics')).

const cfg = $('Extract Session Token').first().json.config;
const zCutoff = cfg.wallZScore ?? 1.5;
const minVolRatio = cfg.minVolumeRatio ?? 1.3;
const bandPct = cfg.strikeBandPct ?? 0.07;
const minLiq = cfg.minLiquidityRating ?? 2;

// Helper: standard deviation
function std(arr) {
  if (arr.length < 2) return 0;
  const m = arr.reduce((a,b) => a+b, 0) / arr.length;
  const v = arr.reduce((a,b) => a + (b-m)*(b-m), 0) / arr.length;
  return Math.sqrt(v);
}

// Helper: clustering around a strike — sum OI within ±$0.50 to capture clusters
function clusterOI(strikes, side, halfWidth = 0.5) {
  return strikes.map(k => {
    const cluster = strikes.filter(s => Math.abs(s.strike - k.strike) <= halfWidth);
    const oi = cluster.reduce((a, s) => a + (s[side+'OI'] || 0), 0);
    const vol = cluster.reduce((a, s) => a + (s[side+'Vol'] || 0), 0);
    return { strike: k.strike, oi, vol };
  });
}

const metricsResp = $('Get Market Metrics').first().json;
const metricsArr = metricsResp?.data?.items || [];

const out = [];
for (const item of items) {
  const prep = $('Pick Near-Term Strikes').itemMatching($itemIndex)?.json;
  if (!prep) continue;
  const symbol = prep.symbol;
  const metrics = metricsArr.find(m => m.symbol === symbol) || {};

  const snap = item.json?.data?.items || [];
  const bySymbol = {};
  for (const q of snap) bySymbol[q.symbol] = q;

  // Underlying snapshot
  const underlying = snap.find(q => q.symbol === symbol) || {};
  const last = parseFloat(underlying.last || underlying.mark || underlying.close || metrics['tos-implied-volatility-index'] || 0) ||
               parseFloat(metrics['close-price'] || 0);
  const prevClose = parseFloat(underlying['prev-close'] || metrics['close-price'] || last);
  const dayVolume = parseFloat(underlying.volume || 0);
  const avgVolume = parseFloat(metrics['average-daily-volume'] || 0);

  if (!last) continue;

  // Map strike index to live OI/Vol
  const lo = last * (1 - bandPct);
  const hi = last * (1 + bandPct);
  const strikes = [];
  for (const k of prep.strikeIndex) {
    if (k.strike < lo || k.strike > hi) continue;
    const c = bySymbol[k.callStreamer] || {};
    const p = bySymbol[k.putStreamer] || {};
    strikes.push({
      strike: k.strike,
      expiration: k.expiration,
      callOI: parseFloat(c['open-interest'] || 0),
      callVol: parseFloat(c.volume || 0),
      putOI: parseFloat(p['open-interest'] || 0),
      putVol: parseFloat(p.volume || 0),
    });
  }
  if (strikes.length < 3) continue;

  // Cluster OI into walls
  const callCluster = clusterOI(strikes, 'call');
  const putCluster = clusterOI(strikes, 'put');
  const callOIs = callCluster.map(c => c.oi);
  const putOIs = putCluster.map(c => c.oi);
  const callMean = callOIs.reduce((a,b)=>a+b,0)/callOIs.length || 0;
  const putMean = putOIs.reduce((a,b)=>a+b,0)/putOIs.length || 0;
  const callStd = std(callOIs);
  const putStd = std(putOIs);

  // Call wall = highest-OI cluster above price with z >= cutoff
  const callWalls = callCluster
    .filter(c => c.strike >= last && callStd > 0 && (c.oi - callMean)/callStd >= zCutoff)
    .sort((a,b) => b.oi - a.oi);
  const putWalls = putCluster
    .filter(c => c.strike <= last && putStd > 0 && (c.oi - putMean)/putStd >= zCutoff)
    .sort((a,b) => b.oi - a.oi);

  const callWall = callWalls[0] || null;
  const putWall = putWalls[0] || null;

  // Volume expansion vs. average
  const volumeRatio = avgVolume > 0 ? dayVolume / avgVolume : 0;

  // Trend: gap + direction (open vs. prev close). Without intraday OHLC, use last vs prev close.
  const changePct = prevClose ? ((last - prevClose) / prevClose) * 100 : 0;
  let trend = 'flat';
  if (changePct > 0.3) trend = 'up';
  else if (changePct < -0.3) trend = 'down';

  // Liquidity rating (tastytrade returns 0-4)
  const liquidityRating = parseInt(metrics['liquidity-rating'] || 0, 10);

  // Pass / fail the screen
  const passVolume = volumeRatio >= minVolRatio;
  const passLiquidity = liquidityRating >= minLiq;
  const passWalls = !!(callWall || putWall);
  const candidate = passVolume && passLiquidity && passWalls;

  // Scalp/mean-reversion playbook
  let setup = 'none';
  if (callWall && putWall) {
    const range = callWall.strike - putWall.strike;
    const pos = range > 0 ? (last - putWall.strike) / range : 0.5;
    if (pos > 0.75 && trend !== 'up') setup = 'mean-revert-from-call-wall';
    else if (pos < 0.25 && trend !== 'down') setup = 'mean-revert-from-put-wall';
    else setup = 'range-scalp';
  } else if (callWall && trend === 'up') {
    setup = 'magnet-to-call-wall';
  } else if (putWall && trend === 'down') {
    setup = 'magnet-to-put-wall';
  }

  // Composite score: walls strength + volume + trend alignment
  const wallScore =
    (callWall ? (callWall.oi - callMean)/(callStd||1) : 0) +
    (putWall  ? (putWall.oi - putMean)/(putStd||1)   : 0);
  const score = +(wallScore * 1.0 + volumeRatio * 1.5 + Math.abs(changePct) * 0.25).toFixed(2);

  out.push({
    json: {
      symbol,
      candidate,
      score,
      last,
      prevClose,
      changePct: +changePct.toFixed(2),
      trend,
      volumeRatio: +volumeRatio.toFixed(2),
      dayVolume,
      avgVolume,
      liquidityRating,
      ivRank: parseFloat(metrics['implied-volatility-index-rank'] || 0),
      expirations: prep.expirations,
      callWall,
      putWall,
      setup,
      strikes,
    }
  });
}
return out;

// === Rank, format and produce the final report ===
const rows = items.map(i => i.json);
rows.sort((a, b) => (b.score || 0) - (a.score || 0));

const now = new Date().toISOString();
const lines = rows.map(r => {
  const cw = r.callWall ? `CW $${r.callWall.strike} (${r.callWall.oi.toLocaleString()} OI)` : 'CW —';
  const pw = r.putWall  ? `PW $${r.putWall.strike} (${r.putWall.oi.toLocaleString()} OI)`  : 'PW —';
  return `${r.symbol.padEnd(6)} $${r.last.toFixed(2).padStart(8)}  ${r.changePct>=0?'+':''}${r.changePct.toFixed(2)}%  vol ${r.volumeRatio}x  ${r.trend.padEnd(4)}  ${pw}  ${cw}  → ${r.setup} (score ${r.score})`;
});

const report = [
  `Tastytrade Day Trade Scanner — ${now}`,
  `Candidates: ${rows.length}`,
  '',
  ...lines
].join('\n');

return [{
  json: {
    generatedAt: now,
    count: rows.length,
    candidates: rows,
    report,
  }
}];
